commands.command:
powershell.exe -NoProfile -ExecutionPolicy Bypass -Command 
$ErrorActionPreference = 'Continue'
Get-Process | Where-Object {
  ($_.ProcessName -like 'AI Workbench*') -or
  ($_.Path -like "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench\\*")
} | Stop-Process -Force -ErrorAction SilentlyContinue
Start-Sleep -Seconds 1
$uninstaller = "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench\\Uninstall AI Workbench.exe"
$installDir = "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench"
$desktopShortcut = "C:\\Users\\胖胖虎\\Desktop\\AI Workbench.lnk"
$startShortcut = "C:\\Users\\胖胖虎\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\AI Workbench.lnk"
if (Test-Path -LiteralPath $uninstaller) {
  $p = Start-Process -FilePath $uninstaller -ArgumentList @('/S') -PassThru -Wait -WindowStyle Hidden
}
Start-Sleep -Seconds 2
foreach ($p in @($desktopShortcut, $startShortcut)) {
  if ($p -and (Test-Path -LiteralPath $p)) { Remove-Item -LiteralPath $p -Force -ErrorAction SilentlyContinue }
}
if (Test-Path -LiteralPath $installDir) { Remove-Item -LiteralPath $installDir -Recurse -Force -ErrorAction SilentlyContinue }
[ordered]@{
  installedExeExists = Test-Path -LiteralPath "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench\\AI Workbench.exe"
  installDirExists = Test-Path -LiteralPath $installDir
} | ConvertTo-Json

