} | Stop-Process -Force -ErrorAction SilentlyContinue
Start-Sleep -Seconds 1
$installer = "F:\\AI-Workbench\\.tmp-3a-actions-30001627121\\ai-workbench-v0.4.6-installer-preflight\\release-v0.4.6-installer\\AI-Workbench-Setup-v0.4.6-x64.exe"
$p = Start-Process -FilePath $installer -ArgumentList @('/S') -PassThru -Wait -WindowStyle Hidden
Start-Sleep -Seconds 5
$shell = New-Object -ComObject WScript.Shell
function ReadShortcut($path) {
  if ($path -and (Test-Path -LiteralPath $path)) {
    $s = $shell.CreateShortcut($path)
    return [ordered]@{ path = $path; target = $s.TargetPath; workingDirectory = $s.WorkingDirectory }
  }
  return $null
}
[ordered]@{
  exitCode = $p.ExitCode
  installedExeExists = Test-Path -LiteralPath "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench\\AI Workbench.exe"
  uninstallerExists = Test-Path -LiteralPath "C:\\Users\\胖胖虎\\AppData\\Local\\Programs\\AIWorkbench\\Uninstall AI Workbench.exe"
  desktopShortcut = ReadShortcut "C:\\Users\\胖胖虎\\Desktop\\AI Workbench.lnk"
  startShortcut = ReadShortcut "C:\\Users\\胖胖虎\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\AI Workbench.lnk"
} | ConvertTo-Json -Depth 6

